public class UnsafeCounter {
    static int count = 0;

    public static void main(String[] args) throws InterruptedException {
        Thread[] threads = new Thread[100];
        for (int i = 0; i < 100; i++) {
            threads[i] = new Thread(() -> {
                for (int j = 0; j < 100; j++) {
                    count++;          // not atomic
                }
            });
            threads[i].start();
        }
        for (Thread t : threads) t.join();
        System.out.println(count);
    }
}
